private:
    std::thread timer_thread;
    std::atomic<bool> running;
    std::chrono::milliseconds interval;
    std::function<void()> callback;

    void timerLoop();

public:
    Pit_timer(std::chrono::milliseconds interval, std::function<void()> callback);
    ~Pit_timer();
};

