#include "zf_driver_pit.h"
#include "zf_driver_file.h"



#include <iostream>
#include <thread>
#include <atomic>
#include <functional>
#include <chrono>



// 实现 timerLoop 函数
void Pit_timer::timerLoop() 
{
    while (running) 
    {
        std::this_thread::sleep_for(interval);
        if (running) 
        {
            callback();
        }
    }
}

// 实现构造函数
Pit_timer::Pit_timer(std::chrono::milliseconds interval, std::function<void()> callback)
    : running(true), interval(interval), callback(callback) 
{
    timer_thread = std::thread(&Pit_timer::timerLoop, this);
}

// 实现析构函数
Pit_timer::~Pit_timer() 
{
    running = false;
    if (timer_thread.joinable()) 
    {
        timer_thread.join();
    }
}

Pit_timer* g_pit_timer = nullptr;
void pit_ms_init(uint32_t ms, std::function<void()> callback)
{
    // 创建一个定时器，周期为 10MS
    g_pit_timer = new Pit_timer(std::chrono::milliseconds(ms), callback);
}

#include "zf_device_uvc.h"


#include <opencv2/imgproc/imgproc.hpp>  // for cv::cvtColor
#include <opencv2/highgui/highgui.hpp> // for cv::VideoCapture
#include <opencv2/opencv.hpp>

#include <iostream> // for std::cerr
#include <fstream>  // for std::ofstream
#include <iostream>
#include <thread>
#include <chrono>
#include <atomic>

using namespace cv;

cv::Mat frame_rgb;      // 构建opencv对象 彩色
cv::Mat frame_rgay;     // 构建opencv对象 灰度

uint8_t *rgay_image;    // 灰度图像数组指针

VideoCapture cap;

int8 uvc_camera_init(const char *path)
{
    cap.open(path);

    if(!cap.isOpened())
    {
        printf("find uvc camera error.\r\n");
        return -1;
    } 
    else 
    {
        printf("find uvc camera Successfully.\r\n");
    }

    cap.set(CAP_PROP_FOURCC, VideoWriter::fourcc('M', 'J', 'P', 'G'));  // 设置格式
    cap.set(CAP_PROP_FRAME_WIDTH, UVC_WIDTH);                           // 设置摄像头宽度
    cap.set(CAP_PROP_FRAME_HEIGHT, UVC_HEIGHT);                         // 设置摄像头高度
    cap.set(CAP_PROP_FPS, UVC_FPS);                                     // 显示屏幕帧率

    printf("get uvc width = %f.\r\n",  cap.get(CAP_PROP_FRAME_WIDTH));
    printf("get uvc height = %f.\r\n", cap.get(CAP_PROP_FRAME_HEIGHT));
    printf("get uvc fps = %f.\r\n",    cap.get(CAP_PROP_FPS));

    return 0;
}


int8 wait_image_refresh()
{
    try 
    {
        // 阻塞式等待图像刷新
        cap >> frame_rgb;
        // cap.read(frame_rgb);
        if (frame_rgb.empty()) 
        {
            std::cerr << "未获取到有效图像帧" << std::endl;
            return -1;
        }
    } 
    catch (const cv::Exception& e) 
    {
        std::cerr << "OpenCV 异常: " << e.what() << std::endl;
        return -1;
    }

    // rgb转灰度
    cv::cvtColor(frame_rgb, frame_rgay, cv::COLOR_BGR2GRAY);

    // cv对象转指针
    rgay_image = reinterpret_cast<uint8_t *>(frame_rgay.ptr(0));

    return 0;
}

